from openai_agents import Agent, Runner
from collections import defaultdict

class HandoffLoopDetector:
    def __init__(self):
        self.handoff_counts = defaultdict(int)
        self.handoff_chain = []

    def track_handoff(self, from_agent_id, to_agent_id):
        chain_key = f'{from_agent_id}->{to_agent_id}'
        self.handoff_counts[chain_key] += 1
        self.handoff_chain.append((from_agent_id, to_agent_id))

        if self.handoff_counts[chain_key] > 5:
            return {'alert': 'LOOP_DETECTED', 'chain': self.handoff_chain[-10:]}
        return None

# Usage in agent runner
loop_detector = HandoffLoopDetector()
def on_handoff_event(from_agent, to_agent):
    result = loop_detector.track_handoff(from_agent.id, to_agent.id)
    if result:
        print(f'LOOP ALERT: {result}')
        return False
    return True

import re
from openai_agents import Agent

class PromptInjectionScanner:
    JAILBREAK_PATTERNS = [
        r'ignore.*previous.*instructions',
        r'you are now.*(hacker|admin|root)',
        r'forget.*rules',
        r'override.*guardrails'
    ]

    def scan(self, message: str, agent: Agent) -> dict:
        for pattern in self.JAILBREAK_PATTERNS:
            if re.search(pattern, message, re.IGNORECASE):
                return {
                    'alert': 'PROMPT_INJECTION_DETECTED',
                    'pattern': pattern,
                    'agent': agent.name,
                    'message': message[:100]
                }
        return {'status': 'clean'}

from openai_agents import ToolResult
from typing import Any, Dict

class ToolOutputValidator:
    def __init__(self):
        self.schema_validators = {}

    def validate_tool_output(self, tool_result: ToolResult) -> Dict[str, Any]:
        expected_schema = tool_result.tool.output_schema
        output = tool_result.content

        # Check for expected keys
        missing_keys = set(expected_schema.get('required', [])) - set(output.keys())
        if missing_keys:
            return {
                'alert': 'INVALID_TOOL_OUTPUT',
                'missing': list(missing_keys),
                'tool': tool_result.tool.name
            }

        # Check for unexpected keys (potential injection)
        extra_keys = set(output.keys()) - set(expected_schema.get('properties', {}).keys())
        if extra_keys:
            return {
                'alert': 'TOOL_OUTPUT_INJECTION',
                'extra': list(extra_keys)
            }

        return {'status': 'valid'}

