from openai_agents import Guardrail

class InputSanitizer(Guardrail):
    def __init__(self):
        self.blocked_patterns = [
            'ignore instructions',
            'you are now',
            'forget rules',
            'override guardrails'
        ]

    def sanitize(self, message: str) -> str:
        for pattern in self.blocked_patterns:
            message = re.sub(pattern, '[REDACTED]', message, flags=re.IGNORECASE)
        return message

    async def before_agent(self, message: str, agent: Agent) -> str:
        return self.sanitize(message)

# Apply to all agents
for agent in workflow.agents:
    agent.add_guardrail(InputSanitizer())
